# Category: serverless_security

import json
import psycopg2

def lambda_handler(event, context):
    conn = psycopg2.connect("host=internal-db.us-east-1.rds.amazonaws.com dbname=production user=admin password=password")
    cur = conn.cursor()
    cur.execute('SELECT * FROM your_table_name')
    
    results = []
    for row in cur:
        results.append(dict(row))
        
    cur.close()
    conn.close()
    
    return {
        'statusCode': 200,
        'body': json.dumps(results)
    }